@page "/board"
@using sv_c6d5f5b17ee7448db72e253c9fb7b873.Components.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats TotalCount="allTasks.Count"
                TodoCount="todoTasks.Count"
                InProgressCount="inProgressTasks.Count"
                DoneCount="doneTasks.Count"
                OverdueCount="allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Tasks="todoTasks"
                     ShowMoveLeft="false"
                     ShowMoveRight="true"
                     OnTaskMoved="HandleTaskMoved"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="inProgressTasks"
                     ShowMoveLeft="true"
                     ShowMoveRight="true"
                     OnTaskMoved="HandleTaskMoved"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn ColumnName="Done"
                     Tasks="doneTasks"
                     ShowMoveLeft="true"
                     ShowMoveRight="false"
                     OnTaskMoved="HandleTaskMoved"
                     OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    private List<TaskItem> allTasks = [];
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] ColumnOrder = ["To Do", "In Progress", "Done"];

    private List<TaskItem> FilteredTasks => string.IsNullOrWhiteSpace(searchText)
        ? allTasks
        : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();

    private List<TaskItem> todoTasks => FilteredTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressTasks => FilteredTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneTasks => FilteredTasks.Where(t => t.Status == "Done").ToList();

    protected override async Task OnInitializedAsync() => await LoadTasks();

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string text) => searchText = text;

    private async Task HandleTaskMoved((int TaskId, string Direction) move)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == move.TaskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(ColumnOrder, task.Status);
        var newIndex = move.Direction == "right" ? currentIndex + 1 : currentIndex - 1;

        if (newIndex < 0 || newIndex >= ColumnOrder.Length) return;

        var newStatus = ColumnOrder[newIndex];

        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            allTasks = allTasks.Select(t => t.Id == task.Id ? t with { Status = newStatus } : t).ToList();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreated(AddTaskForm.NewTaskRequest request)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(request.Title, request.Assignee, request.Priority, request.DueDate);
            allTasks.Add(created with { Status = request.Status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

