        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string DefaultStatus { get; set; } = default!;
    [Parameter] public EventCallback<NewTaskRequest> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title)) return;

        saving = true;
        await OnSave.InvokeAsync(new NewTaskRequest(title.Trim(), assignee.Trim(), priority, dueDate, DefaultStatus));
        saving = false;
    }

    private async Task HandleCancel() => await OnCancel.InvokeAsync();

    public record NewTaskRequest(string Title, string Assignee, string Priority, DateTime DueDate, string Status);
}
"}

