    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, string Direction)> OnTaskMoved { get; set; }
    [Parameter] public EventCallback<AddTaskForm.NewTaskRequest> OnTaskCreated { get; set; }

    private bool showForm;

    private async Task HandleMoveLeft(int taskId) =>
        await OnTaskMoved.InvokeAsync((taskId, "left"));

    private async Task HandleMoveRight(int taskId) =>
        await OnTaskMoved.InvokeAsync((taskId, "right"));

    private async Task HandleTaskSaved(AddTaskForm.NewTaskRequest request)
    {
        await OnTaskCreated.InvokeAsync(request);
        showForm = false;
    }
}
"}

